284→fn bash_exec(input: &Value, stream_cb: &mut dyn FnMut(&str)) -> Result<String, String> {
285→    let command = input["command"]
286→        .as_str()
287→        .ok_or("Missing required parameter: command")?;
288→
289→    if is_denied_command(command) {
290→        return Err(format!("Command blocked by safety guard: {command}"));
291→    }
292→
293→    let timeout = Duration::from_secs(120);
294→    let deadline = Instant::now() + timeout;
295→
296→    let mut child = Command::new("bash")
297→        .arg("-c")
298→        .arg(command)
299→        .stdout(Stdio::piped())
300→        .stderr(Stdio::piped())
301→        .spawn()
302→        .map_err(|e| format!("Failed to spawn bash: {e}"))?;
303→
304→    let stdout = child.stdout.take().unwrap();
305→    let stderr = child.stderr.take().unwrap();
306→
307→    let (tx_out, rx) = mpsc::channel::<String>();
308→    let tx_err = tx_out.clone();
309→
310→    // Stdout reader thread
311→    std::thread::spawn(move || {
312→        let reader = BufReader::with_capacity(4096, stdout);
313→        let mut buf = Vec::new();
314→        let mut r = reader;
315→        loop {
316→            buf.clear();
317→            match r.read_until(b'\n', &mut buf) {
318→                Ok(0) => break,
319→                Ok(_) => {
320→                    let s = String::from_utf8_lossy(&buf).to_string();
321→                    if tx_out.send(s).is_err() {
322→                        break;
323→                    }
324→                }
325→                Err(_) => break,
326→            }
327→        }
328→    });
329→
330→    // Stderr reader thread
331→    std::thread::spawn(move || {
332→        let reader = BufReader::with_capacity(4096, stderr);
333→        let mut buf = Vec::new();
334→        let mut r = reader;
335→        loop {
336→            buf.clear();
337→            match r.read_until(b'\n', &mut buf) {
338→                Ok(0) => break,
339→                Ok(_) => {
340→                    let s = String::from_utf8_lossy(&buf).to_string();
341→                    if tx_err.send(s).is_err() {
342→                        break;
343→                    }
344→                }
345→                Err(_) => break,
346→            }
347→        }
348→    });
349→
350→    // Drop our copy of tx so rx closes when threads finish
351→    let mut output = String::new();
352→    let mut timed_out = false;
353→
354→    loop {
355→        if Instant::now() >= deadline {
356→            let _ = child.kill();
357→            timed_out = true;
358→            break;
359→        }
360→
361→        match rx.recv_timeout(Duration::from_millis(50)) {
362→            Ok(chunk) => {
363→                stream_cb(&chunk);
364→                output.push_str(&chunk);
365→            }
366→            Err(mpsc::RecvTimeoutError::Timeout) => {
367→                // Check if process has exited
368→                match child.try_wait() {
369→                    Ok(Some(_)) => {
370→                        // Process finished — drain remaining
371→                        while let Ok(chunk) = rx.try_recv() {
372→                            stream_cb(&chunk);
373→                            output.push_str(&chunk);
374→                        }
375→                        break;
376→                    }
377→                    Ok(None) => continue,
378→                    Err(_) => break,
379→                }
380→            }
381→            Err(mpsc::RecvTimeoutError::Disconnected) => {
382→                // Both threads done
383→                let _ = child.wait();
384→                break;
385→            }
386→        }
387→    }
388→
389→    if timed_out {
390→        if output.is_empty() {
391→            return Err(format!("Command timed out after 120s: {command}"));
392→        }
393→        return Err(format!(
394→            "Command timed out after 120s (partial output):\n{output}"
395→        ));
396→    }
397→
398→    let status = child
399→        .wait()
400→        .map_err(|e| format!("Failed to wait for process: {e}"))?;
401→
402→    if status.success() {
403→        Ok(output)
404→    } else {
405→        let code = status.code().unwrap_or(-1);
406→        if output.is_empty() {
407→            Err(format!("Command failed with exit code {code}"))
408→        } else {
409→            Err(format!("Command failed with exit code {code}:\n{output}"))
410→        }
411→    }
412→}
