414→fn edit_exec(input: &Value) -> Result<String, String> {
415→    let file_path = input["file_path"]
416→        .as_str()
417→        .ok_or("Missing required parameter: file_path")?;
418→    let old_str = input["old_str"]
419→        .as_str()
420→        .ok_or("Missing required parameter: old_str")?;
421→    let new_str = input["new_str"]
422→        .as_str()
423→        .ok_or("Missing required parameter: new_str")?;
424→    let replace_all = input["replace_all"].as_bool().unwrap_or(false);
425→
426→    let path = Path::new(file_path);
427→
428→    // Empty old_str: create file (if missing) or append (if exists)
429→    if old_str.is_empty() {
430→        if path.exists() {
431→            // Append
432→            let mut content =
433→                std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {e}"))?;
434→            content.push_str(new_str);
435→            std::fs::write(path, &content).map_err(|e| format!("Cannot write file: {e}"))?;
436→            return Ok(format!("Appended to {file_path}"));
437→        } else {
438→            // Create with parent dirs
439→            if let Some(parent) = path.parent() {
440→                std::fs::create_dir_all(parent)
441→                    .map_err(|e| format!("Cannot create directories: {e}"))?;
442→            }
443→            std::fs::write(path, new_str).map_err(|e| format!("Cannot create file: {e}"))?;
444→            return Ok(format!("Created {file_path}"));
445→        }
446→    }
447→
448→    // Normal edit: read, find, replace
449→    let content = std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {e}"))?;
450→
451→    let metadata = std::fs::metadata(path).map_err(|e| format!("Cannot read metadata: {e}"))?;
452→    if metadata.len() > 102_400 {
453→        return Err(format!(
454→            "File too large for edit: {} bytes (limit: 100KB)",
455→            metadata.len()
456→        ));
457→    }
458→
459→    if replace_all {
460→        if !content.contains(old_str) {
461→            return Err(format!("Text not found in {file_path}"));
462→        }
463→        let new_content = content.replace(old_str, new_str);
464→        let count = content.matches(old_str).count();
465→        std::fs::write(path, &new_content).map_err(|e| format!("Cannot write file: {e}"))?;
466→        return Ok(format!("Replaced {count} occurrences in {file_path}"));
467→    }
468→
469→    // Single exact match
470→    let count = content.matches(old_str).count();
471→    if count == 0 {
472→        return Err(format!("Text not found in {file_path}"));
473→    }
474→    if count > 1 {
475→        return Err(format!(
476→            "Found {count} matches in {file_path} (expected exactly 1). Use replace_all=true for bulk replacement."
477→        ));
478→    }
479→
480→    let new_content = content.replacen(old_str, new_str, 1);
481→    std::fs::write(path, &new_content).map_err(|e| format!("Cannot write file: {e}"))?;
482→
483→    Ok(format!("Edited {file_path}"))
484→}
