486→fn grep_exec(input: &Value) -> Result<String, String> {
487→    let pattern = input["pattern"]
488→        .as_str()
489→        .ok_or("Missing required parameter: pattern")?;
490→    let path = input["path"].as_str().unwrap_or(".");
491→    let file_type = input["file_type"].as_str();
492→    let case_sensitive = input["case_sensitive"].as_bool().unwrap_or(true);
493→
494→    // Check rg is installed
495→    let rg_check = Command::new("which").arg("rg").output();
496→    match rg_check {
497→        Ok(output) if !output.status.success() => {
498→            return Err(
499→                "ripgrep (rg) is not installed. Install it with: brew install ripgrep (macOS) or apt install ripgrep (Linux)"
500→                    .to_string(),
501→            );
502→        }
503→        Err(_) => {
504→            return Err(
505→                "ripgrep (rg) is not installed. Install it with: brew install ripgrep (macOS) or apt install ripgrep (Linux)"
506→                    .to_string(),
507→            );
508→        }
509→        _ => {}
510→    }
511→
512→    let mut cmd = Command::new("rg");
513→    cmd.arg("--max-count=50")
514→        .arg("--line-number")
515→        .arg("--no-heading")
516→        .arg("--color=never");
517→
518→    if !case_sensitive {
519→        cmd.arg("-i");
520→    }
521→
522→    if let Some(ft) = file_type {
523→        cmd.arg("--type").arg(ft);
524→    }
525→
526→    cmd.arg(pattern).arg(path);
527→
528→    let output = cmd.output().map_err(|e| format!("Failed to run rg: {e}"))?;
529→
530→    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
531→    let stderr = String::from_utf8_lossy(&output.stderr).to_string();
532→
533→    if !output.status.success() {
534→        let code = output.status.code().unwrap_or(-1);
535→        if code == 1 {
536→            // rg exit 1 = no matches
537→            return Ok("No matches found".to_string());
538→        }
539→        if !stderr.is_empty() {
540→            return Err(stderr.trim().to_string());
541→        }
542→        return Err(format!("rg exited with code {code}"));
543→    }
544→
545→    let result = stdout.trim().to_string();
546→    if result.is_empty() {
547→        Ok("No matches found".to_string())
548→    } else {
549→        Ok(result)
550→    }
551→}
