        // block, block, allow(reset), block, block → consecutive should be 2
        let steps: &[bool] = &[false, false, true, false, false]; // true=allow, false=block
        let mut consecutive = 0usize;
        for &is_allow in steps {
            if is_allow {
                consecutive = 0;
            } else {
                consecutive += 1;
            }
