        let config_path = dir.path().join("hooks.toml");
        fs::write(
            &config_path,
            r#"
[[hooks]]
event = "PreToolUse"
command = "echo allow"
match_tool = "Bash"

[[hooks]]
event = "PostToolUse"
command = "echo continue"
timeout_ms = 3000
"#,
