/// Generate `all_tool_schemas()` from a declarative tool list.
/// Each entry: name, description, schema (serde_json::Value).
macro_rules! tools {
    ( $( $name:expr, $desc:expr, $schema:expr );+ $(;)? ) => {
        pub fn all_tool_schemas() -> Vec<serde_json::Value> {
            vec![
                $(
                    serde_json::json!({
                        "name": $name,
                        "description": $desc,
                        "input_schema": $schema,
                    }),
                )+
            ]
        }
    };
}

tools! {
