        assert!(result.is_ok());
        assert!(result.unwrap().contains("3 occurrences"));

        let content = std::fs::read_to_string(&file).unwrap();
        assert_eq!(content, "xxx bbb xxx ccc xxx");
        let _ = std::fs::remove_file(&file);
    }

    #[test]
    fn edit_single_match_rejects_duplicates() {
