    // --- ToolEffect classification tests ---

    #[test]
    fn tool_effect_pure_tools() {
        assert_eq!(tool_effect("Read"), ToolEffect::Pure);
        assert_eq!(tool_effect("Glob"), ToolEffect::Pure);
        assert_eq!(tool_effect("Grep"), ToolEffect::Pure);
    }

    #[test]
    fn tool_effect_mutating_tools() {
        assert_eq!(tool_effect("Bash"), ToolEffect::Mutating);
        assert_eq!(tool_effect("Edit"), ToolEffect::Mutating);
    }

    #[test]
    fn tool_effect_unknown_defaults_to_mutating() {
        assert_eq!(tool_effect("Unknown"), ToolEffect::Mutating);
        assert_eq!(tool_effect("FutureTool"), ToolEffect::Mutating);
        assert_eq!(tool_effect(""), ToolEffect::Mutating);
    }

    #[test]
    fn tool_effect_exhaustive_for_all_tools() {
        let schemas = all_tool_schemas();
        for schema in &schemas {
            let name = schema["name"].as_str().unwrap();
            let effect = tool_effect(name);
            // Every known tool must have an explicit classification (not fall through to unknown)
            match name {
                "Read" | "Glob" | "Grep" => {
                    assert_eq!(effect, ToolEffect::Pure, "{name} should be Pure")
                }
                "Bash" | "Edit" => {
                    assert_eq!(effect, ToolEffect::Mutating, "{name} should be Mutating")
                }
                _ => panic!("New tool {name} needs explicit ToolEffect classification"),
            }
        }
    }

    // --- bash_exec output cap tests ---

    #[test]
    fn bash_output_cap_constant_is_1mb() {
        assert_eq!(BASH_OUTPUT_LIMIT, 1_048_576);
    }

    #[test]
    fn bash_large_output_is_truncated() {
        // Generate ~2MB of output — exceeds the 1MB cap
        let result = dispatch_tool(
            "Bash",
            &json!({"command": "dd if=/dev/zero bs=1024 count=2048 2>/dev/null | xxd -p"}),
            &mut |_| {},
        );
        assert!(result.is_err(), "should return Err on output cap");
        let err = result.unwrap_err();
        assert!(
            err.contains("1MB limit"),
            "error should mention 1MB limit: {err}"
        );
        assert!(
            err.contains("truncated"),
            "error should mention truncation: {err}"
        );
    }

    #[test]
    fn bash_normal_output_not_truncated() {
        // Small output should pass through fine
        let result = dispatch_tool("Bash", &json!({"command": "echo hello"}), &mut |_| {});
        assert!(result.is_ok());
        assert_eq!(result.unwrap().trim(), "hello");
    }

    // --- Edit size limit tests (create/append paths) ---

    #[test]
    fn edit_append_rejects_oversized_file() {
        let dir = std::env::temp_dir().join("forgeflare_test_edit");
        let _ = std::fs::create_dir_all(&dir);
        let file = dir.join("test_oversized_append.txt");
        // Create a file larger than 100KB
        let big = "x".repeat(110_000);
        std::fs::write(&file, &big).unwrap();

        let result = dispatch_tool(
            "Edit",
            &json!({
                "file_path": file.to_str().unwrap(),
                "old_str": "",
                "new_str": "more data",
            }),
            &mut |_| {},
        );
        assert!(result.is_err(), "should reject append to oversized file");
        assert!(result.unwrap_err().contains("too large"));
        let _ = std::fs::remove_file(&file);
    }

    #[test]
    fn edit_create_rejects_oversized_content() {
        let dir = std::env::temp_dir().join("forgeflare_test_edit");
        let _ = std::fs::create_dir_all(&dir);
        let file = dir.join("test_oversized_create.txt");
        let _ = std::fs::remove_file(&file);

        let big_content = "x".repeat(110_000);
        let result = dispatch_tool(
            "Edit",
            &json!({
                "file_path": file.to_str().unwrap(),
                "old_str": "",
                "new_str": big_content,
            }),
            &mut |_| {},
        );
        assert!(result.is_err(), "should reject oversized create");
        assert!(result.unwrap_err().contains("too large"));
        // File should not have been created
        assert!(!file.exists());
    }

